/** biome-ignore-all lint/suspicious/noCommentText: TypeScript directive comments needed for component */
import { ActionPageFinancePreset } from '@domain/actionPages';
import { useTotalAmount } from '@pages/ActionPages/pages/PublicActionPage/ActionPageView/ActionPageLayout/ActionPageBody/hooks';
import { formatCurrency } from '@ui/utils/formatCurrency';
import { tw } from '@utils/useTailwind';
import valid from 'card-validator';
import { clsx } from 'clsx';
import currency from 'currency.js';
import { CSSProperties, useMemo } from 'react';
import { useFormContext } from 'react-hook-form';
import { Button } from '../../../Button';
import { Label } from '../../../Label';
import { MaskedInputControl } from '../../../MaskedInputControl';
import { FeaturedAmountBadge } from './FeaturedAmountBadge';

type Props = {
  actionButtonBgColor?: string;
  actionButtonClassName?: string;
  actionButtonHoverBgColor?: string;
  actionButtonProps?: { className?: string; style?: CSSProperties };
  actionButtonTextColor?: string;
  amountPresetsOther?: boolean;
  amounts?: ActionPageFinancePreset[];
  enableButtons?: boolean;
  maximumAmount?: number | null;
  minimumAmount?: number;
  otherAmount?: string;
  selectedAmount?: ActionPageFinancePreset | null;
  setOtherAmount: (val: string | undefined) => void;
  setSelectedAmount: (amount: ActionPageFinancePreset | null) => void;
  setShowOtherInput: (val: boolean) => void;
  showLoadingOnAmounts?: boolean;
  showOtherInput?: boolean;
  ticketAmount: number;
  totalFees: number;
};

// Flexes the layout based upon how many amounts are given
// 1 - full width
// 2 - 50/50
// 3 - 33/33/33
// 4 - 25/25/25/25
// 5 - 33/33/33 and 50/50
// 6 - 33/33/33
// 7 - and up, is all going to be 25
// Exceptions are buttons with amount and description, which will always be 100% width
export const AmountPresetsContainer = ({
  actionButtonBgColor,
  actionButtonClassName,
  actionButtonHoverBgColor,
  actionButtonProps,
  actionButtonTextColor,
  amountPresetsOther = false,
  amounts,
  enableButtons = true,
  maximumAmount,
  minimumAmount,
  otherAmount,
  selectedAmount,
  setOtherAmount,
  setSelectedAmount,
  setShowOtherInput,
  showLoadingOnAmounts,
  showOtherInput = false,
  ticketAmount,
  totalFees,
}: Props) => {
  const presetAmounts = amounts ?? [];
  const { watch } = useFormContext();
  const promoCodeDiscount = watch('promoCodeDiscount') ?? 0;
  const cardNumber = watch('vaultToken');

  const formCardType = watch('cardType');
  const cardType: 'american-express' | 'visa' | 'mastercard' | 'discover' | string | undefined =
    useMemo(() => valid.number(cardNumber)?.card?.type, [cardNumber]);
  const pageType = formCardType || cardType;
  const customerCoversTheFees = pageType === 'storefront' ? true : watch('customerCoveredFees');

  const donationAmount = useTotalAmount();

  const error = useMemo(() => {
    if (
      !!maximumAmount &&
      donationAmount + ticketAmount + (customerCoversTheFees ? totalFees : 0) - promoCodeDiscount >
        maximumAmount
    ) {
      const maximumCurrencyValue = currency(maximumAmount / 100);
      const formattedMaximumAmount = formatCurrency(maximumCurrencyValue.intValue, {
        hideDecimal: maximumCurrencyValue.cents() === 0,
      });

      return `Maximum limit of ${formattedMaximumAmount}`;
    }

    if (
      !!minimumAmount &&
      donationAmount + ticketAmount !== 0 &&
      donationAmount + ticketAmount + (customerCoversTheFees ? totalFees : 0) - promoCodeDiscount <
        minimumAmount * 100 &&
      !(
        ticketAmount === donationAmount + ticketAmount &&
        donationAmount + ticketAmount === promoCodeDiscount
      )
    ) {
      const minimumCurrencyValue = currency(minimumAmount);
      const formattedMinimumAmount = formatCurrency(minimumCurrencyValue.intValue, {
        hideDecimal: minimumCurrencyValue.cents() === 0,
      });

      return `Minimum amount of ${formattedMinimumAmount} required.`;
    }

    return undefined;
  }, [
    customerCoversTheFees,
    donationAmount,
    maximumAmount,
    minimumAmount,
    promoCodeDiscount,
    ticketAmount,
    totalFees,
  ]);

  const buttonClasses = clsx(actionButtonClassName && actionButtonClassName, tw`h-[64px] grow`);

  return (
    <div className={showOtherInput ? 'flex w-full flex-col' : 'mt-2 flex w-full flex-col'}>
      <div className={tw`flex flex-wrap justify-center gap-2`}>
        {presetAmounts.map((amount) => (
          <Button
            className={clsx(
              buttonClasses,
              amount.description ? 'w-full min-w-full' : 'min-w-[20%]',
              amount.description
                ? 1
                : presetAmounts.length === 5 || presetAmounts.length === 6
                  ? // Needs to be below 33%, less to account for margins to get 1/3
                    'flex-[0_0_30%]'
                  : // Needs to be below 25%, less to account for margins to get 1/4
                    'flex-[0_0_20%]'
            )}
            data-selected={
              !selectedAmount
                ? undefined
                : amount.amount === selectedAmount.amount
                  ? 'selected'
                  : 'not-selected'
            }
            isActive={amount.amount === selectedAmount?.amount}
            isDisabled={amount.amount !== selectedAmount?.amount && showLoadingOnAmounts}
            isLoading={amount === selectedAmount && showLoadingOnAmounts}
            key={amount.id ?? amount.amount}
            onClick={() => {
              if (!enableButtons) {
                return;
              }

              setShowOtherInput(false);
              setOtherAmount(undefined);
              setSelectedAmount(amount);
            }}
            style={{
              // CSS hack: use variables for hover states (since Tailwind can't do dynamic classes)
              '--ap-btn-bg-color': actionButtonBgColor ?? '#28c290',
              '--ap-btn-hover-bg-color': actionButtonHoverBgColor ?? '#14AE7C',
              '--ap-btn-text-color': actionButtonTextColor ?? '#fff',
            }}
            variant="donationAmount"
            {...actionButtonProps}
          >
            {amount.description ? (
              <div className="m-1 flex w-full items-center justify-between">
                {amount.amount}
                <div className="flex items-center justify-end gap-2">
                  <Label className="text-current ml-20 whitespace-normal text-right !text-inherit">
                    {amount.description}
                  </Label>
                  {amount.featured && (
                    <FeaturedAmountBadge
                      bgColor={actionButtonTextColor}
                      className={actionButtonClassName ?? ''}
                      color={actionButtonBgColor}
                      label={amount.featuredLabel}
                      variant="floating"
                    />
                  )}
                </div>
              </div>
            ) : amount.featured ? (
              <div className="flex flex-col">
                {amount.amount}
                <FeaturedAmountBadge
                  bgColor={actionButtonTextColor}
                  className={actionButtonClassName ?? ''}
                  color={actionButtonBgColor}
                  label={amount.featuredLabel}
                  variant="bottom"
                />
              </div>
            ) : (
